function Get-ParsecIngredientOperations {
    return @{ capture = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) Get-ParsecProcessCaptureResult -Arguments $Arguments }; apply = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) $process = Start-Process -FilePath $Arguments.file_path -ArgumentList @($Arguments.arguments) -PassThru; New-ParsecResult -Status 'Succeeded' -Message "Started process '$($Arguments.file_path)'." -Outputs @{ process_id = [int] $process.Id; process_name = [string] $process.ProcessName; file_path = [string] $Arguments.file_path } }; verify = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) $processId = if ($null -ne $ExecutionResult -and $ExecutionResult.Outputs.process_id) { [int] $ExecutionResult.Outputs.process_id } elseif ($Arguments.ContainsKey('process_id')) { [int] $Arguments.process_id } else { $null }; $process = if ($null -ne $processId) { Get-Process -Id $processId -ErrorAction SilentlyContinue } elseif ($Arguments.ContainsKey('process_name')) { @(Get-Process -Name $Arguments.process_name -ErrorAction SilentlyContinue) | Select-Object -First 1 } else { $null }; if ($null -eq $process) { return New-ParsecResult -Status 'Failed' -Message 'Process is not running.' }; New-ParsecResult -Status 'Succeeded' -Message 'Process is running.' -Observed @{ process_id = [int] $process.Id; process_name = [string] $process.ProcessName } }; reset = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) $processId = if ($null -ne $ExecutionResult -and $ExecutionResult.Outputs.process_id) { [int] $ExecutionResult.Outputs.process_id } elseif ($Arguments.ContainsKey('process_id')) { [int] $Arguments.process_id } else { $null }; $process = if ($null -ne $processId) { Get-Process -Id $processId -ErrorAction SilentlyContinue } elseif ($Arguments.ContainsKey('process_name')) { @(Get-Process -Name $Arguments.process_name -ErrorAction SilentlyContinue) | Select-Object -First 1 } else { $null }; if ($null -eq $process) { return New-ParsecResult -Status 'Succeeded' -Message 'Process was already stopped.' }; Stop-Process -Id $process.Id -ErrorAction SilentlyContinue; New-ParsecResult -Status 'Succeeded' -Message "Stopped process id '$($process.Id)'." } }
}